DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "PGchoicemacros.pl",
  "contextForm.pl",
  "parserLinearRelation.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
($X, $Y) = random_subset(2, 'a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
Context("LinearRelation")->variables->are($X => 'Real', $Y => 'Real');
Context()->noreduce('(-x)-y', '(-x)+y');
$A[0] = list_random(-5..-2, 2..5);
$A[1] = $A[0];
@B = (1,1);
@C = (-9..9)[NchooseK(19,2)];
$left[0] = Formula("$A[0] $X + $B[0] $Y")->reduce;
$f[0] = Formula("$left[0] = $C[0]")->reduce;
$h[1] = non_zero_random(-5, 5);
$k[1] = $C[1] - $A[1]*$h[1];
$right[1] = Formula("-$A[1] ($X - $h[1]) + $k[1]")->reduce;
$f[1] = Formula("$Y = $right[1]");
Context()->strings->remove("NONE");
Context()->strings->add(
  "no solutions" => {},
);
for (
  "no solution",
  "none",
  "there are no solutions",
  "the solution set is empty",
  "solution set is empty",
  "empty set",
  "∅",
  "{}",
  "{ }",
  "{  }",
  "{   }"
) {
  Context()->strings->add($_ => {alias => "no solutions"});
}
Context()->strings->add(
  "infinitely many solutions" => {},
);
for (
  "infinitely many",
  "infinite solution set",
  "infinite",
  "the solution set is infinite",
  "solution set is infinite"
) {
  Context()->strings->add($_ => {alias => "infinitely many solutions"});
}
$solution = Compute("no solutions");
$answer = $solution->cmp(
  typeMatch => List("$X = 0, $Y = 0"),
  mathQuillOpts => 'disabled'
);
# Note $B[0] is 1
$sol[0] = $left[0]->substitute($Y => $right[1]);
$sol[1] = Formula("$A[0] $X - $A[1] $X + ($A[1]*$h[1]) + $k[1]")->reduce;
$sol[2] = Formula("$B[0]*($A[1]*$h[1] + $k[1])")->reduce;

############################################################
# Body
############################################################

BEGIN_PGML
Solve the system of equations using substitution.

[`\newcommand{\amp}{&}\left\{
                  \begin{alignedat}{4}
                  \amp [$f[0]] \\
                  \amp [$f[1]]
                  \end{alignedat}
                  \right.
                `]

[@KeyboardInstructions('Write the solution in the format [`[$X] = \text{number}, [$Y] = \text{number}\text{.}`] If there is no solution, enter [|no solutions|]*. If there are infinitely many solutions, enter [|infinitely many solutions|]*.')@]**

[_]{$answer}{16}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
Since [`[$Y]`] is already isolated in the second equation line, we will use that and substitute [`[$right[1]]`] in for [`[$Y]`] in the first equation:

[```\newcommand{\amp}{&}
\begin{aligned}
[$sol[0]]\amp=[$C[0]]\\
[$sol[1]]\amp=[$C[0]]\\
[$sol[2]]\amp=[$C[0]]
\end{aligned}
```]

This is an outright false equation, so there is no solution.

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
